define i64 @test_pr128441_commuted4_negative(i64 %x, i64 %y) {
  %iszero = icmp ne i64 %x, %y
  %xor = xor i64 %x, %y
  %cttz = call i64 @llvm.cttz.i64(i64 %xor, i1 true)
  %sel = select i1 %iszero, i64 64, i64 %cttz
  ret i64 %sel
}

